class Solution {
public:
    string shortestPalindrome(string s) {
        string rev = s;
        reverse(rev.begin(), rev.end());
        string concat = s + "#" + rev;
        int lps[concat.size()];
        int len = 0;
        lps[0] = 0;
        int i = 1;
        while (i < concat.size()) {
            if (concat[i] == concat[len]) {
                len++;
                lps[i] = len;
                i++;
            } else {
                if (len != 0) {
                    len = lps[len - 1];
                } else {
                    lps[i] = 0;
                    i++;
                }
            }
        }
        return rev.substr(0, s.size() - lps.back()) + s;
    }
};
```
